#include <bits/stdc++.h>
using namespace std;

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    int lengthOfCycle(ListNode* head) {
        ListNode *slow = head, *fast = head;
        while (fast && fast->next) {
            slow = slow->next;
            fast = fast->next->next;
            if (slow == fast) {
                // cycle length
                int cnt = 1;
                ListNode *cur = slow->next;
                while (cur != slow) {
                    ++cnt;
                    cur = cur->next;
                }
                return cnt;
            }
        }
        return 0;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    int cycleIndex;
    cin >> cycleIndex;
    // build nodes
    vector<ListNode*> nodes;
    nodes.reserve(n);
    for (int v : vals) nodes.push_back(new ListNode(v));
    for (int i = 0; i < n - 1; ++i) nodes[i]->next = nodes[i + 1];
    ListNode* head = n ? nodes[0] : nullptr;
    if (cycleIndex >= 0 && cycleIndex < n) {
        nodes.back()->next = nodes[cycleIndex];
    }
    Solution sol;
    int ans = sol.lengthOfCycle(head);
    cout << ans << "\n";
    // clean up (optional for short-lived program)
    // Note: if there is a cycle, naive delete would loop forever; skip.
    return 0;
}
